def verify_webhook_signature(payload_body: str, signature_header: str, secret: str) -> bool:
    """Verify the webhook signature using HMAC-SHA256 to ensure authenticity."""
    if not signature_header or not secret:
        return False

    expected_signature = hmac.new(
        secret.encode("utf-8"),
        payload_body.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    # Use constant-time comparison to prevent timing attacks
    return hmac.compare_digest(f"sha256={expected_signature}", signature_header)


def validate_nesting_depth(obj: Any, current_depth: int = 0) -> bool:
    """Validate that JSON object nesting doesn't exceed maximum depth."""
    if current_depth > MAX_NESTING_DEPTH:
        return False

    if isinstance(obj, dict):
        for value in obj.values():
            if not validate_nesting_depth(value, current_depth + 1):
                return False
    elif isinstance(obj, list):
        for item in obj:
            if not validate_nesting_depth(item, current_depth + 1):
                return False

    return True


def sanitize_string(value: str, max_length: int = 1024) -> str:
    """Sanitize string input by truncating and removing control characters."""
    if not isinstance(value, str):
        return ""
    # Truncate to max length
    value = value[:max_length]
    # Remove null bytes and other dangerous control characters
    value = value.replace("\x00", "")
    return value


